  audio: Blob;
  /**
     * The format of input audio. Options are 'pcm_s16le_16' or 'other'.
     * For pcm_s16le_16, the input audio must be 16-bit PCM at a 16kHz sample rate, single channel (mono).
     * @nullable
     */
  file_format?: ElevenLabsSpeechToSpeechRequestFileFormat;
  /**
     * Identifier of the model that will be used. Query GET /v1/models to list available models.
     * The model needs to have support for speech to speech (can_do_voice_conversion property).
     */
  model_id?: string;
  /**
     * If set, will remove the background noise from your audio input using our audio isolation model.
     * Only applies to Voice Changer.
     */
