  /**
     * Text that came before this request, used to improve speech continuity.
     * @nullable
     */
  previous_text?: string | null;
  /**
     * List of pronunciation dictionary locators (id, version_id). Maximum 3 per request.
     * @maxItems 3
     * @nullable
     */
