/**
 * Request body for the fal PATINA extract model (fal-ai/patina/material/extract): extract a texture from an input image and generate a complete tiling PBR material.
 */
export interface FalPatinaMaterialExtractRequest {
  /** Expand the prompt with an LLM for richer detail. */
  enable_prompt_expansion?: boolean;
  /** Enable the safety checker for generated images. */
  enable_safety_checker?: boolean;
  /** Output texture dimensions. Either a preset string (square_hd, square, portrait_4_3, portrait_16_9, landscape_4_3, landscape_16_9) or an object with integer width and height. Defaults to square_hd. */
  image_size?: unknown;
  /** URL of the image to extract a texture from. */
  image_url: string;
  /** Which PBR maps to predict. Defaults to all five. */
  maps?: string[];
  /** Number of texture images to generate. */
  num_images?: number;
  /** Number of denoising steps for texture generation. */
  num_inference_steps?: number;
  /** Output image format for textures and PBR maps: jpeg, png, or webp. */
  output_format?: string;
  /** Describe which texture to extract from the image. */
  prompt: string;
  /** Random seed for reproducible generation. */
  seed?: number;
  /** How much to transform the input image. */
  strength?: number;
  /** Tile size in latent space (64 = 512px, 128 = 1024px). */
  tile_size?: number;
  /** Tile stride in latent space. */
  tile_stride?: number;
  /** Tiling direction: both, horizontal, or vertical. */
  tiling_mode?: string;
  /** Upscale factor for predicted PBR maps. One of 0 (no upscaling), 2 (2x), or 4 (4x), as a string or number. */
  upscale_factor?: unknown;
}

/**
 * A generated texture or PBR map image.
 */
export interface FalPatinaMaterialImage {
  /** The PBR map type (basecolor, normal, roughness, metalness, height). Absent for the base texture image. */
  map_type?: string;
  /** URL of the generated image. */
  url?: string;
}

/**
 * Request body for the fal PATINA material generation model.
 */
export interface FalPatinaMaterialRequest {
  /** Expand the prompt with an LLM for richer detail. */
  enable_prompt_expansion?: boolean;
  /** Enable the safety checker for generated images. */
  enable_safety_checker?: boolean;
  /** Output texture dimensions. Either a preset string (square_hd, square, portrait_4_3, portrait_16_9, landscape_4_3, landscape_16_9) or an object with integer width and height. Defaults to square_hd (1024x1024). Drives the per-megapixel price. */
  image_size?: unknown;
  /** URL of an input image for image-to-image or inpainting. */
  image_url?: string;
  /** Which PBR maps to predict. Each predicted map adds a per-megapixel charge. Defaults to all five. */
  maps?: string[];
  /** URL of a mask image for inpainting. Requires image_url. */
  mask_url?: string;
  /** Number of texture images to generate. */
  num_images?: number;
  /** Number of denoising steps for texture generation. */
  num_inference_steps?: number;
  /** Output image format for textures and PBR maps: jpeg, png, or webp. */
  output_format?: string;
  /** The text prompt describing the material/texture to generate. */
  prompt: string;
  /** Random seed for reproducible generation. */
  seed?: number;
  /** How much to transform the input image. Only used when image_url is provided. */
  strength?: number;
  /** Tile size in latent space (64 = 512px, 128 = 1024px). */
  tile_size?: number;
  /** Tile stride in latent space. */
  tile_stride?: number;
  /** Tiling direction: both, horizontal, or vertical. */
  tiling_mode?: string;
  /** Upscale factor for predicted PBR maps. One of 0 (no upscaling), 2 (2x), or 4 (4x), as a string or number. Upscaling adds a per-(pre-upscaling)-megapixel-per-map surcharge. */
  upscale_factor?: unknown;
}

