/**
 * A single NDJSON event from the Sonilo streaming response. Additional event types beyond those listed may appear; unknown types should be ignored by clients.
 */
export type SoniloStreamEvent = {
  /** @minimum 0 */
  copy_index: number;
  display_tags: string[];
  /** @minimum 0 */
  prompt_index: number;
  /** @minimum 0 */
  stream_index: number;
  /** Short natural-language description of the generated track. */
  summary?: string;
  title: string;
  type: 'title';
} | {
  channels: number;
  /** Base64-encoded AAC in fMP4 fragments; concatenate per stream_index. */
  data: string;
  /** @minimum 1 */
  num_streams: number;
  sample_rate: number;
  /** @minimum 0 */
  stream_index: number;
  type: 'audio_chunk';
} | {
  type: 'complete';
} | {
  code?: string;
  message: string;
  type: 'error';
};

