export const getSoniloVideoToMusicGenerateUrl = () => {




  return `/proxy/sonilo/v2m/generate`
}

/**
 * Generate music from a video using Sonilo video-to-music AI.
 * Accepts either a video file upload or a video URL, with an optional prompt.
 * Returns a streaming NDJSON response with one or more parallel audio streams
 * (titles, audio chunks, and completion events).
 * Max video duration: 6 minutes. Max upload size: 300MB.
 * @summary Generate music from video
 */
export const soniloVideoToMusicGenerate = async (soniloVideoToMusicRequest: SoniloVideoToMusicRequest, options?: RequestInit): Promise<soniloVideoToMusicGenerateResponse> => {
    const formData = new FormData();
Object.entries(soniloVideoToMusicRequest ?? {}).forEach(([key, value]) => {
  if (value !== undefined && value !== null) {
    if ((typeof File !== 'undefined' && value instanceof File) || value instanceof Blob) {
      formData.append(key, value);
    } else if (typeof Buffer !== 'undefined' && Buffer.isBuffer(value)) {
      formData.append(key, new Blob([Uint8Array.from(value)]));
    } else if (Array.isArray(value)) {
      value.forEach(v => {
        if ((typeof File !== 'undefined' && v instanceof File) || v instanceof Blob) {
          formData.append(key, v);
        } else if (typeof Buffer !== 'undefined' && Buffer.isBuffer(v)) {
          formData.append(key, new Blob([Uint8Array.from(v)]));
        } else {
          formData.append(key, typeof v === 'object' ? JSON.stringify(v) : String(v));
        }
      });
    } else if (typeof value === 'object') {
      formData.append(key, JSON.stringify(value));
    } else {
      formData.append(key, String(value));
    }
  }
});

  return customInstance<soniloVideoToMusicGenerateResponse>(getSoniloVideoToMusicGenerateUrl(),
  {
    ...options,
    method: 'POST'
    ,
    body: formData
  }
);}





